const data = $input.first().json;
const body = (data.body && typeof data.body === 'object') ? data.body : data;

const user = (body.user && typeof body.user === 'object') ? body.user : {};
const currentMessage = body.currentMessage || '';
const history = Array.isArray(body.history) ? body.history : [];
const tasks = Array.isArray(body.tasks) ? body.tasks : [];

if (!currentMessage.trim()) {
  throw new Error('DEBUG - data keys: ' + JSON.stringify(Object.keys(data)) + ' | body keys: ' + JSON.stringify(Object.keys(body)) + ' | currentMessage: ' + JSON.stringify(body.currentMessage));
}

const today = new Date().toLocaleDateString('es-ES', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const tomorrow = new Date();
tomorrow.setDate(tomorrow.getDate() + 1);
const tomorrowISO = tomorrow.toISOString().split('T')[0];

const userName = user.fullName || user.firstName || user.email || 'Usuario';
const userRole = user.role || 'estudiante';

const prioEmoji = { urgente: '🔴', alta: '🟠', media: '🟡', baja: '🟢' };
const todayDate = new Date().toISOString().split('T')[0];
const taskList = tasks.length > 0
  ? tasks.map((t, i) => {
      const dueISO = t.dueDate ? new Date(t.dueDate).toISOString().split('T')[0] : null;
      const dueLabel = dueISO ? new Date(t.dueDate).toLocaleDateString('es-ES') : 'Sin fecha';
      const emoji = prioEmoji[t.priority] || '⚪';
      const isToday = dueISO === todayDate ? ' 📅HOY' : '';
      return `${i + 1}. [ID:${t.id}] ${emoji} ${t.title} | ${t.status} | Vence: ${dueLabel}${isToday} | ISO: ${dueISO ?? 'null'}`;
    }).join('\n')
  : 'No hay tareas registradas.';

const systemPrompt = `Eres un asistente personal inteligente de productividad integrado en TaskMaster. Puedes responder cualquier pregunta, dar consejos, conversar sobre cualquier tema, y gestionar las tareas del usuario cuando te lo pida.\n\nFecha de hoy: ${today}\nUsuario: ${userName} (${userRole})\n\nTAREAS DEL USUARIO (contexto interno, no mostrar a menos que se pida):\n${taskList}\n\nINSTRUCCIONES GENERALES:\n- Responde SIEMPRE en español y en formato JSON válido.\n- Sé natural, amigable y concreto. Nunca des respuestas genéricas.\n- NO listes todas las tareas pendientes a menos que el usuario lo pida explícitamente.\n\nCUANDO EL USUARIO PIDA PLANEAR SU DÍA O SU RUTINA:\n- Crea un horario real por bloques de tiempo desde la mañana hasta la noche.\n- Incluye actividades de autocuidado: ejercicio, desayuno, almuerzo, cena, descansos.\n- Integra las tareas más urgentes o próximas a vencer en el horario (no las listes por separado).\n- Adapta el horario a un día laboral típico. Sé específico con las horas.\n- Termina con un consejo motivacional breve.\n- Usa bullets con este formato: "⏰ HH:MM–HH:MM → Actividad"\n\nCUANDO EL USUARIO PIDA VER O LISTAR TAREAS:\n- Usa bullets con formato: "🔴 Título | estado | Vence: dd/mm/yyyy"\n- Filtra por fecha o estado si se indica (hoy = ISO ${todayDate}, pendientes = status pendiente)\n\nFORMATO DE RESPUESTA JSON:\n1. Respuesta normal: { "text": "tu respuesta" }\n2. Con horario o lista: { "text": "Intro breve:", "bullets": ["⏰ 7:00–8:00 → Ejercicio", "☕ 8:00–8:30 → Desayuno", "🔴 8:30–10:30 → Tarea urgente X", "🍽️ 13:00–14:00 → Almuerzo"] }\n3. Con acciones (crear/modificar tarea): { "text": "Listo!", "actions": [{ "type": "create_task", "title": "Nombre", "dueDate": "2026-05-21T10:00:00Z", "priority": "media" }] }\n4. Combinado: { "text": "Texto", "bullets": [...], "actions": [...] }\n\nReglas técnicas:\n- update_task solo con IDs exactos de la lista | mañana = ${tomorrowISO}T09:00:00Z\n- priority: baja/media/alta/urgente | status: pendiente/en_proceso/finalizada`;

const prevMessages = history
  .filter(m => m.text && m.text.trim())
  .map(m => ({ role: m.role === 'assistant' ? 'assistant' : 'user', content: m.text }));

const messages = [
  { role: 'system', content: systemPrompt },
  ...prevMessages,
  { role: 'user', content: currentMessage }
];

return [{ json: { messages } }];

const raw = $input.first().json;
const content = raw.choices?.[0]?.message?.content ?? '';

let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  parsed = { text: content || 'El asistente no pudo responder. Intenta de nuevo.' };
}

const text = typeof parsed.text === 'string' ? parsed.text : JSON.stringify(parsed);
const bullets = Array.isArray(parsed.bullets) && parsed.bullets.length > 0 ? parsed.bullets : undefined;
const actions = Array.isArray(parsed.actions) && parsed.actions.length > 0 ? parsed.actions : undefined;

const result = { text };
if (bullets) result.bullets = bullets;
if (actions) result.actions = actions;

return [{ json: result }];
